define float @fdiv_constant_numerator_fmul_fast(float %x) {
  %t1 = fdiv fast float 2.000000e+03, %x
  %t3 = fmul fast float %t1, 6.000000e+03
  ret float %t3
}

define float @fdiv_constant_numerator_fmul_precdiv(float %x) {
  %t1 = fdiv float 2.000000e+03, %x
  %t3 = fmul reassoc float %t1, 6.000000e+03
  ret float %t3
}

define <3 x float> @mul_neg_zero_nnan_ninf_vec(<3 x float> nofpclass(nan inf) %a) {
entry:
  %ret = fmul <3 x float> %a, <float -0.000000e+00, float poison, float poison>
  ret <3 x float> %ret
}

define half @mul_zero_nnan(half %x) {
  %r = fmul nnan half %x, 0xH0000
  ret half %r
}

define <2 x float> @mul_zero_nnan_vec_poison(<2 x float> %x) {
  %r = fmul nnan <2 x float> %x, <float 0.000000e+00, float poison>
  ret <2 x float> %r
}

